import { index, jsonb, pgTable, text, timestamp, uuid } from "drizzle-orm/pg-core";

export const productEvents = pgTable(
  "product_events",
  {
    id: uuid("id").primaryKey().defaultRandom(),
    organizationId: text("organization_id"),
    actorId: text("actor_id"),
    eventType: text("event_type").notNull(),
    source: text("source").notNull().default("app"),
    metadata: jsonb("metadata").$type<Record<string, unknown>>().notNull().default({}),
    occurredAt: timestamp("occurred_at", { withTimezone: true }).defaultNow().notNull(),
  },
  (event) => [
    index("product_events_organization_idx").on(event.organizationId),
    index("product_events_type_idx").on(event.eventType),
    index("product_events_occurred_at_idx").on(event.occurredAt),
  ],
);

export type ProductEventInput = {
  eventType: string;
  actorId?: string;
  organizationId?: string;
  source?: string;
  metadata?: Record<string, unknown>;
};

export function createProductEvent(input: ProductEventInput) {
  return {
    eventType: input.eventType,
    actorId: input.actorId,
    organizationId: input.organizationId,
    source: input.source ?? "app",
    metadata: input.metadata ?? {},
  };
}

export const activationEventTypes = [
  "workspace.created",
  "api_key.created",
  "first_request.succeeded",
  "billing.checkout_started",
] as const;

import { activationEventTypes } from "@/lib/stackfoundry/plg-metrics";

export default function PLGMetricsPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">PLG Metrics</h1>
        <p className="text-muted-foreground">
          Track activation events and product-led growth signals across workspaces.
        </p>
      </div>
      <div className="grid gap-3">
        {activationEventTypes.map((eventType) => (
          <section key={eventType} className="rounded-lg border p-4">
            <h2 className="font-medium">{eventType}</h2>
            <p className="text-sm text-muted-foreground">Activation event</p>
          </section>
        ))}
      </div>
    </main>
  );
}
